namespace BloodAndBittersteel.Features.NightsWatch
{
    public static class NightsWatchDialogs
    {
        public const string SendToNightWatchNormal = "{=bab_nightwatch_send_normal}The old gods and the new watch us this day. I could end your life for what you have done, but I grant you this chance at redemption. Swear your vows, take the black, and stand as a brother of the Night's Watch.";
        public const string SendToNightWatchDevious = "{=bab_nightwatch_send_devious}You've played your move and lost. I will not grant you the mercy of death, you are to take the black.";
        public const string PrisonerAgreesNormal = "{=bab_nightwatch_prisoner_agrees_normal}As you command, my lord. Better the cold of the Wall than the grave. I will take the black and speak the vows before a heart tree if the gods allow it.";
        public const string PrisonerAgreesHonourable = "{=bab_nightwatch_prisoner_agrees_honourable}The gods will judge me there. I will go willingly, take the black, and uphold the honour of my house even in exile.";
        public const string PrisonerAgreesDevious = "{=bab_nightwatch_prisoner_agrees_devious}Fine. Send me north. Better to freeze in black than rot here. Who knows — I may yet outlive you all up there.";

        public const string PrisonerRefusesNormal = "{=bab_nightwatch_prisoner_refuses_normal}I will not take the black. You are no liege of mine and I am no cutthroat to be dragged to the crows.";
        public const string PrisonerRefusesHonourable = "{=bab_nightwatch_prisoner_refuses_honourable}The vows of the Night's Watch are sacred, but this punishment dishonours us both. Kill me if you must — I will not stain the black with my unwilling oath.";
        public const string PrisonerRefusesDevious = "{=bab_nightwatch_prisoner_refuses_devious}Never. I'd rather the headsman's axe than become one of your cursed black crows.";
        public const string PrisonerRefusesPlayerRebellionRelationNegativeLordHonourable = "{=bab_nightwatch_prisoner_refuses_player_rebellion_relation_negative_lord_honourable}Daeron the Falseborn sits on a stolen throne, and you think I will don black to save my skin? Kill me here, usurper. A quick blade is more mercy than I deserve if I live to serve a king who isn't true";
        public const string PrisonerRefusesPlayerRebellionRelationNegative = "{=bab_nightwatch_prisoner_refuses_player_rebellion_relation_negative}I would sooner feed my heart to the crows than wear the black. Send me to the seven hells if you must, but do not insult my house by casting me out like a common deserter.";
        public const string PrisonerRefusesPlayerRebellion = "{=bab_nightwatch_prisoner_refuses_player_rebellion}I would rather die holding the Black Dragon high. Do you think I will crawl to the North to huddle in a castle of snow? I will not live to see the realm bow to a Dornish puppet.";
        public const string PrisonerRefusesPlayerRebellionLordDevious = "{=bab_nightwatch_prisoner_refuses_player_rebellion_lord_devious}Treason is only a word used by the victors. If Daemon wins, you would be the one begging for the Wall. Do not offer me exile as if it is a gift, it is a slow death for a man who knows his true king.";
        public const string PrisonerRefusesPlayerLoyalistRelationNegativeLordHonourable = "{=bab_nightwatch_prisoner_refuses_player_loyalist_relation_negative_lord_honourable}You call Daemon the rightful king? Daemon was a bastard given a sword, while Daeron was born to the throne and crowned by the High Septon himself. I will not wear the black to appease a usurper’s conscience. If my loyalty to the Red Dragon is treason, then let the axe fall here, where the gods can see it";
        public const string PrisonerRefusesPlayerLoyalistLordDevious = "{=bab_nightwatch_prisoner_refuses_player_loyalist_lord_devious}You think the cold will cleanse me of my sins? I have no sins to cleanse! I fought for the legitimate heir against a bastard’s ambition. Daeron offered peace to the realm, and I gave him my sword to protect that peace. I don't recognise your bastard as my king nor as any king at all. Therefore you cannot send me to the Wall.";

        public const string ExecuteAfterRefusalNormal = "{=bab_nightwatch_executenormal}So be it. have him drawn and quarted as the mongrel dog he is";
        public const string ExecuteAfterRefusalHonourable = "{=bab_nightwatch_execute_honourable}A pity it comes to this. You were a lord once. Die with what honour remains to you.";
        public const string ExecuteAfterRefusalDevious = "{=bab_nightwatch_execute_devious}Wrong choice. String him up slowly — let him feel the cold before the end. Make an example of this fool.";
        public const string SpareNormal = "{=bab_nightwatch_spare_normal}Very well. Rot in the dungeons then. Perhaps time will change your mind about the Wall.";
        public const string SpareHonourable = "{=bab_nightwatch_spare_honourable}You speak with courage, if not wisdom. I will not slay you for it. May the gods guide you to a better choice in time.";
    }
}
